import{C as n,o as i,c as r,a5 as s,E as o}from"./chunks/framework.CW28V7p_.js";const u=JSON.parse('{"title":"2. Instructions & cross-program invocation","description":"","frontmatter":{},"headers":[],"relativePath":"module-3/2-instructions.md","filePath":"module-3/2-instructions.md","lastUpdated":1780937944000}'),l={name:"module-3/2-instructions.md"},h=Object.assign(l,{setup(c){const e={id:"m3-2-instructions",title:"🧠 Mini-check: Instructions & CPI",intro:"3 питання — instructions і cross-program calls.",questions:[{type:"mcq",q:"Що з цього вірно про cross-program invocation (CPI)?",options:["Один program може викликати інший program у тому ж TX","CPI calls counted у TX compute budget","Calling program може передавати accounts отриманні з TX до called program","Cycle CPI (A → B → A) автоматично дозволений"],correct:[0,1,2],explanation:"CPI дозволяє composability — DEX викликає Token Program, lending викликає Oracle, etc. Cycles НЕ дозволені (max depth ~4). Module 3.2."},{type:"explain",q:"Поясни своїми словами як працює Sealevel parallel execution. Чому Solana може це робити коли Ethereum не може?",ideal:`Sealevel — Solana runtime для parallel TX execution. Як працює:

1. Scheduler читає account lists від всіх pending TXs у block being built
2. Для кожної pair TXs визначає conflict: "чи туч обидві same writable account?"
3. Якщо conflict — TXs execute sequentially. Якщо disjoint — паралельно on different CPU cores.
4. Validator з 32+ cores може execute 32+ TXs одночасно якщо non-conflicting.

Чому Solana може, Ethereum не може:
- Solana TX має EXPLICIT pre-declared account list. Scheduler знає upfront які accounts touched.
- Ethereum smart contract може dynamically access будь-яку storage slot under contract address. Сcheduler can't predict accesses без executing the TX → can't safely parallelize.

This design choice (pre-declared accounts) — fundamental enabler Solana throughput. Tradeoff: developer must enumerate accounts upfront (mental overhead).`,explanation:"Pre-declared accounts → parallel scheduling. Ethereum dynamic access → sequential. Module 3.2."},{type:"compare",q:"У чому різниця між instruction account marked writable vs read-only?",ideal:`Writable: instruction може modify account (lamports або data). Scheduler treatить writable accounts як exclusive — тільки одна TX may write до конкретного account at a time.

Read-only: instruction може ТІЛЬКИ read account. Multiple TXs можуть concurrently read same account (parallel-safe).

Чому matters: TX explicitly tags кожен account як writable або read-only через TransactionMessage header. Це дає scheduler info для parallelism:
- Якщо TX1 writes account X, TX2 reads X → sequential (TX2 must wait)
- Якщо TX1 reads X, TX2 reads X → parallel OK (no conflict)
- Якщо TX1 writes X, TX2 writes Y → parallel OK (different accounts)

Developer має tagнути правильно. Якщо declare writable що actually read-only — TX лишається correct але loses parallelization opportunity. Якщо declare read-only що writes — runtime catches violation, TX fails.`,explanation:"Writable = exclusive lock, read-only = shared. Affects parallelism. Module 3.2."}]};return(p,a)=>{const t=n("Quiz");return i(),r("div",null,[a[0]||(a[0]=s(`<h1 id="_2-instructions-cross-program-invocation" tabindex="-1">2. Instructions &amp; cross-program invocation <a class="header-anchor" href="#_2-instructions-cross-program-invocation" aria-label="Permalink to &quot;2. Instructions &amp; cross-program invocation&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Instruction</strong> — atomic unit of execution всередині TX. Specifies: which program виконати, який data передати, які accounts (з TX&#39;s account list) program може torcho.</p><p>Programs можуть <strong>call other programs</strong> через <strong>CPI</strong> (Cross-Program Invocation). Це enable composability — DEX aggregator може chain through кілька DEXes у одній TX.</p><h2 id="концепти" tabindex="-1">Концепти <a class="header-anchor" href="#концепти" aria-label="Permalink to &quot;Концепти&quot;">​</a></h2><h3 id="instruction-anatomy" tabindex="-1">Instruction anatomy <a class="header-anchor" href="#instruction-anatomy" aria-label="Permalink to &quot;Instruction anatomy&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Instruction {</span></span>
<span class="line"><span>    program_id: Pubkey,           // який program викликати</span></span>
<span class="line"><span>    accounts: Vec&lt;AccountMeta&gt;,   // які accounts передати (subset з TX account list)</span></span>
<span class="line"><span>    data: Vec&lt;u8&gt;,                // bytes argument (program-specific format)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AccountMeta {</span></span>
<span class="line"><span>    pubkey: Pubkey,</span></span>
<span class="line"><span>    is_signer: bool,</span></span>
<span class="line"><span>    is_writable: bool,</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Один TX містить 1+ instructions. Виконуються <strong>послідовно</strong> в order. Atomic — все або нічого.</p><h3 id="writable-vs-read-only-accounts" tabindex="-1">Writable vs read-only accounts <a class="header-anchor" href="#writable-vs-read-only-accounts" aria-label="Permalink to &quot;Writable vs read-only accounts&quot;">​</a></h3><p>Кожен account у instruction tagged: writable (можна modify) або read-only.</p><p>Чому matters: Sealevel scheduler паралелізує TXs по account access patterns.</p><table tabindex="0"><thead><tr><th>TX1 access</th><th>TX2 access</th><th>Same account?</th><th>Parallel OK?</th></tr></thead><tbody><tr><td>Write X</td><td>Write X</td><td>Yes</td><td>No (lock)</td></tr><tr><td>Write X</td><td>Read X</td><td>Yes</td><td>No</td></tr><tr><td>Read X</td><td>Read X</td><td>Yes</td><td>Yes</td></tr><tr><td>Write X</td><td>Write Y</td><td>Different</td><td>Yes</td></tr></tbody></table><p>Solana може виконати десятки TXs паралельно якщо вони touch disjoint writable sets.</p><h3 id="signer-vs-non-signer" tabindex="-1">Signer vs non-signer <a class="header-anchor" href="#signer-vs-non-signer" aria-label="Permalink to &quot;Signer vs non-signer&quot;">​</a></h3><p>Кожен account також tagged: signer (signature required) або non-signer.</p><p>Signer means: instruction вимагає authorization від owner цього account. Наприклад, SOL transfer requires sender signature.</p><p>Number signers per TX = <code>header.num_required_signatures</code>. Перший signer = fee payer.</p><h3 id="instruction-data-format" tabindex="-1">Instruction data format <a class="header-anchor" href="#instruction-data-format" aria-label="Permalink to &quot;Instruction data format&quot;">​</a></h3><p><code>data: Vec&lt;u8&gt;</code> — arbitrary bytes. Format defined by program.</p><p>Native programs зазвичай мають simple encoding:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Program transfer instruction:</span></span>
<span class="line"><span>  data = [0x02, ...transfer_amount_u64]</span></span>
<span class="line"><span>   ↑     ↑</span></span>
<span class="line"><span>   |     8 bytes little-endian amount</span></span>
<span class="line"><span>   discriminator (2 = transfer instruction)</span></span></code></pre></div><p>BPF programs зазвичай використовують <strong>borsh</strong> або <strong>bincode</strong> serialization. Anchor framework додає 8-byte instruction discriminator + arguments.</p><p>Як developer — ти не пишеш raw bytes. SDK (web3.js, anchor) генерує data за тебе. Як operator — рідко treba бачити raw, але корисно знати що data це bytes which program decodes.</p><h3 id="cross-program-invocation-cpi" tabindex="-1">Cross-Program Invocation (CPI) <a class="header-anchor" href="#cross-program-invocation-cpi" aria-label="Permalink to &quot;Cross-Program Invocation (CPI)&quot;">​</a></h3><p><strong>CPI</strong> — коли one program (caller) calls another (callee) within same TX execution.</p><p>Приклад — Token Program transfer (внутрішньо):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User TX:</span></span>
<span class="line"><span>  Instruction: token_program.transfer(...)</span></span>
<span class="line"><span>    ↓ CPI</span></span>
<span class="line"><span>    Token Program executes:</span></span>
<span class="line"><span>      - Check ownership</span></span>
<span class="line"><span>      - Decrement source account amount</span></span>
<span class="line"><span>      - Increment destination account amount</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User TX with CPI through aggregator:</span></span>
<span class="line"><span>  Instruction: jupiter_program.swap(USDC, JTO, amount)</span></span>
<span class="line"><span>    ↓ CPI</span></span>
<span class="line"><span>    Jupiter executes:</span></span>
<span class="line"><span>      ↓ CPI to Raydium</span></span>
<span class="line"><span>      Raydium executes: swap USDC → SOL</span></span>
<span class="line"><span>      ↓ CPI to Orca</span></span>
<span class="line"><span>      Orca executes: swap SOL → JTO</span></span>
<span class="line"><span>      ↓ CPI to Token Program</span></span>
<span class="line"><span>      Token Program transfers JTO to user</span></span></code></pre></div><p>Кожна вкладена call counts towards TX&#39;s <strong>compute budget</strong>. Max depth ~4 levels (prevents infinite recursion).</p><h3 id="composability-through-cpi" tabindex="-1">Composability through CPI <a class="header-anchor" href="#composability-through-cpi" aria-label="Permalink to &quot;Composability through CPI&quot;">​</a></h3><p>CPI робить Solana programs <strong>composable</strong> — нові апликації можуть build on existing programs:</p><ul><li>DEX aggregator (Jupiter) calls DEXes (Raydium, Orca) через CPI</li><li>Lending protocols (Kamino) call Token Program для transfers, Oracle для prices</li><li>NFT marketplaces (Magic Eden) call Metaplex Metadata Program для NFT data</li></ul><p>Це similar concept to &quot;function calls&quot; у regular programming — але across <strong>decentralized</strong> programs (не контрольованих one entity).</p><h3 id="accounts-передача-у-cpi" tabindex="-1">Accounts передача у CPI <a class="header-anchor" href="#accounts-передача-у-cpi" aria-label="Permalink to &quot;Accounts передача у CPI&quot;">​</a></h3><p>Calling program передає subset своїх accounts to called program. Permissions inherited:</p><ul><li>Якщо у TX account marked writable → calling program може pass it як writable до callee</li><li>Якщо у TX account signer → callee receives signer status</li></ul><p>PDAs (Program Derived Addresses) — special case: program може &quot;sign&quot; за свого PDA через <code>invoke_signed</code> (since PDA has no private key, program itself is authority).</p><h2 id="compute-budget" tabindex="-1">Compute budget <a class="header-anchor" href="#compute-budget" aria-label="Permalink to &quot;Compute budget&quot;">​</a></h2><p>TX має <strong>compute budget</strong> — max instructions allowed для execute. Default: 200,000 Compute Units (CU). Max: 1,400,000 CU.</p><p>Кожна operation costs CUs:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Approx CU</th></tr></thead><tbody><tr><td>Simple SOL transfer</td><td>~150 CU</td></tr><tr><td>Token transfer</td><td>~3000 CU</td></tr><tr><td>Token mint</td><td>~5000 CU</td></tr><tr><td>Complex DEX swap</td><td>~80000-150000 CU</td></tr><tr><td>Heavy CPI chain (aggregator)</td><td>~500000+ CU</td></tr></tbody></table><p>Якщо TX exceeds budget — fails з &quot;Computation budget exceeded&quot;.</p><p>User може increase budget via ComputeBudget instruction:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Instruction 0: ComputeBudget.setComputeUnitLimit(1_000_000)</span></span>
<span class="line"><span>Instruction 1: &lt;main instruction&gt;</span></span></code></pre></div><p>Module 3.3 deeper на fees та compute pricing.</p><h2 id="sealevel-—-parallel-execution" tabindex="-1">Sealevel — parallel execution <a class="header-anchor" href="#sealevel-—-parallel-execution" aria-label="Permalink to &quot;Sealevel — parallel execution&quot;">​</a></h2><p>Solana runtime <strong>Sealevel</strong> schedules TXs across CPU cores:</p><ol><li><strong>Read account lists</strong> від всіх pending TXs у block being built</li><li><strong>Build dependency graph</strong>: TX1 → TX2 conflict якщо they share writable account</li><li><strong>Parallel execute</strong> independent TXs across cores</li><li><strong>Sequential</strong> group conflicting TXs у chains</li></ol><p>Result: validator з 32 cores може process 32+ TXs simultaneously якщо non-conflicting. Це і root reason Solana ~3000+ TPS — паралелізм.</p><p>Ethereum (для contrast): EVM serial execution — одна TX at a time. Sharding propose parallel — but each shard internally still serial.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="validator-submits-vote-txs" tabindex="-1">Validator submits vote TXs <a class="header-anchor" href="#validator-submits-vote-txs" aria-label="Permalink to &quot;Validator submits vote TXs&quot;">​</a></h3><p>Кожен 400ms slot твій validator builds and signs vote TX, broadcasts через TPU. Це single-instruction TX:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vote TX:</span></span>
<span class="line"><span>  Instruction: vote_program.vote(slot, hash, lockouts, ...)</span></span></code></pre></div><p>Vote program не використовує CPI — simple direct call.</p><h3 id="stake-activation-tx" tabindex="-1">Stake activation TX <a class="header-anchor" href="#stake-activation-tx" aria-label="Permalink to &quot;Stake activation TX&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delegate-stake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stake.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> VOTE_PUBKEY</span></span></code></pre></div><p>Builds TX з instructions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Instruction 0: Compute budget (optional)</span></span>
<span class="line"><span>Instruction 1: Stake Program.delegate(stake, vote, ...)</span></span></code></pre></div><p>Stake program внутрішньо може CPI до Clock sysvar для timing data — read-only.</p><h3 id="multi-instruction-operations" tabindex="-1">Multi-instruction operations <a class="header-anchor" href="#multi-instruction-operations" aria-label="Permalink to &quot;Multi-instruction operations&quot;">​</a></h3><p><code>solana create-vote-account</code> builds TX з кількома instructions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Instruction 0: System Program.create_account(new vote account, lamports, owner=Vote Program)</span></span>
<span class="line"><span>Instruction 1: Vote Program.initialize(vote account, identity, voter authority, ...)</span></span></code></pre></div><p>Atomic — обидві instructions виконуються або жодна.</p><h2 id="hands-on-exercise" tabindex="-1">Hands-on exercise <a class="header-anchor" href="#hands-on-exercise" aria-label="Permalink to &quot;Hands-on exercise&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Подивись на recent SOL transfer TX (з explorer Solscan можеш взяти signature)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Або budovan локально:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --keypair</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR_KEYPAIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">RECIPIEN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.001</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devnet</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Після signature returned, перевір:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> confirm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">G</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devnet</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Output показує:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - Instructions: 1 (system program transfer)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - Accounts: from, to, system program</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - Compute units used (~150 для transfer)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - Fee paid (5000 lamports = 0.000005 SOL базова)</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,66)),o(t,{data:e}),a[1]||(a[1]=s('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#c"><code>CPI</code></a>, <a href="/glossary#c"><code>Cross-program invocation</code></a>, <a href="/glossary#s"><code>Sealevel</code></a>, <a href="/glossary#c"><code>Compute Unit</code></a>, <a href="/glossary#c"><code>Compute budget</code></a>, <a href="/glossary#a"><code>AccountMeta</code></a>, <a href="/glossary#d"><code>Discriminator</code></a>, <a href="/glossary#b"><code>Borsh</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/runtime/programs" target="_blank" rel="noreferrer">Anza: Instructions</a></li><li><a href="https://www.anchor-lang.com/docs/cross-program-invocations" target="_blank" rel="noreferrer">Anchor: CPI Examples</a></li><li><a href="https://www.helius.dev/blog/solana-compute-units" target="_blank" rel="noreferrer">Helius: Solana Compute Units</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-3/1-tx-anatomy">← 1. TX anatomy</a> | <strong>Наступне:</strong> <a href="/module-3/3-fees">3. Fees, priority fees, compute →</a></p>',6))])}}});export{u as __pageData,h as default};
